import { Card } from '@/types'

export const FALLBACK_CARDS: Card[] = [{"id":1,"stmt":"An edtech app launched push notifications with a visibly sad, tearful mascot guilt-tripping users who missed their daily lesson. The ethics team flagged it as manipulative. Thousands of users tweeted screenshots mocking it.","dec":"ship","co":"Duolingo","yr":"2022","color":"#58CC02","expl":"The guilt-tripping Duo owl became iconic. Streak-tied notifications became Duolingo's single most powerful retention lever, contributing to 4.5x DAU growth over four years. The discomfort was the point.","pat":"Emotional design that mirrors how users actually feel outperforms rational nudges, even when it feels uncomfortable to ship.","url":"https://www.lennysnewsletter.com/p/behind-the-product-duolingo-streaks","domain":"duolingo.com"},{"id":2,"stmt":"A language learning app borrowed weekly competitive ranking systems directly from mobile casino games, with promotions, demotions, and rivalries against strangers. Every education consultant said it was the wrong fit.","dec":"ship","co":"Duolingo","yr":"2019","color":"#58CC02","expl":"Leaderboards modeled on casual games became the Retention Team's first breakthrough. The fourth iteration blew away all prior attempts and moved DAU meaningfully for the first time.","pat":"Do not be precious about where your best mechanic comes from. Steal what works from adjacent domains.","url":"https://www.lennysnewsletter.com/p/how-duolingo-reignited-user-growth","domain":"duolingo.com"},{"id":3,"stmt":"A B2B messaging startup's CEO publicly told a tech publication their own product was 'terrible' and the company should be 'humiliated' for releasing it. The PR team tried to kill the quote.","dec":"ship","co":"Slack","yr":"2014","color":"#4A154B","expl":"Stewart Butterfield's radical self-criticism became a cultural rallying cry for craftsmanship. The emotional connection users formed drove word-of-mouth spread from company to company.","pat":"Radical honesty about product quality builds more trust than any marketing copy. Users can tell when a company genuinely cares.","url":"https://www.lennysnewsletter.com/p/slack-founder-stewart-butterfield","domain":"slack.com"},{"id":4,"stmt":"An email client required every new user to complete a mandatory 30-minute live onboarding call with a team member before gaining any access. Zero self-serve. Investors said it was completely unscalable.","dec":"ship","co":"Superhuman","yr":"2018","color":"#FF6B35","expl":"Superhuman's forced onboarding created power users from day one. People who learned the tool properly stayed and evangelized. The unscalable process seeded a fanatical user base.","pat":"Unscalable things that create deep engagement compound into scalable outcomes. Optimize for the right users, not the most users.","url":"https://www.lennysnewsletter.com/p/superhumans-secret-to-success-rahul-vohra","domain":"superhuman.com"},{"id":5,"stmt":"A productivity startup refused to hire any salespeople until $10M ARR, repeatedly turning away enterprise clients who required sales support. Investors said the team was leaving millions on the table.","dec":"ship","co":"Notion","yr":"2020","color":"#37352F","expl":"When Notion eventually hired sales, the inbound pipeline was enormous. Every rep was immediately productive. Product-led growth did the qualification and trust-building first.","pat":"Premature sales hires before product-market fit burn cash. Let the product prove the motion first, then amplify it.","url":"https://www.lennysnewsletter.com/p/inside-notion-ivan-zhao","domain":"notion.so"},{"id":6,"stmt":"A startup ran out of money and couldn't raise more. To fund operations, the two founders designed custom political cereal boxes, sold them for $40 each, and mailed them to journalists' desks.","dec":"ship","co":"Airbnb","yr":"2008","color":"#FF5A5F","expl":"Obama O's and Cap'n McCain's sold out and generated $30K. More importantly, the hustle convinced Y Combinator to back Airbnb. The stunt became one of the most retold founding stories in tech.","pat":"Extreme resourcefulness signals extreme founder quality. Do the ridiculous thing if it proves you will do whatever it takes.","url":"https://www.lennysnewsletter.com/p/the-social-radar-jessica-livingston","domain":"airbnb.com"},{"id":7,"stmt":"A gaming company with 45 employees and a deeply loved multiplayer game shut down that game entirely to pivot to an internal messaging tool nobody outside the company had asked for.","dec":"ship","co":"Slack","yr":"2012","color":"#4A154B","expl":"Stewart Butterfield shut down Glitch, a beloved game, to focus on the internal tool his teams used to communicate. That tool became Slack, which sold to Salesforce for $27.7B.","pat":"Sometimes your best product is the one you built for yourself. Pay attention to the tools you cannot stop using internally.","url":"https://www.lennysnewsletter.com/p/slack-founder-stewart-butterfield","domain":"slack.com"},{"id":8,"stmt":"A CEO hired actors to stage a fake protest outside a competitor's major conference, complete with picket signs saying 'the end of software is near.' The competitor called the police.","dec":"ship","co":"Salesforce","yr":"2000","color":"#00A1E0","expl":"Local TV stations covered the 'protest' as real news. Salesforce got free national coverage at exactly the moment they needed to be seen as a disruptive force. It helped establish their anti-establishment brand.","pat":"Earned media at launch requires doing something genuinely unexpected. Manufactured moments can be more powerful than paid ones.","url":"https://www.lennysnewsletter.com/p/behind-the-founder-marc-benioff","domain":"salesforce.com"},{"id":9,"stmt":"A startup spent seven years close to bankruptcy, rebuilt their product twice, and was days from shutting down when they launched a new AI feature with nothing but a single tweet. No press. No launch event.","dec":"ship","co":"Bolt","yr":"2023","color":"#6B47ED","expl":"Bolt hit $20M ARR two months after that tweet and was approaching $40M ARR by the time of recording. The seven years building WebContainer technology was the exact foundation that made the AI product possible.","pat":"Sometimes you are not a failed company. You are a company that has not found its moment yet. Keep building.","url":"https://www.lennysnewsletter.com/p/inside-bolt-eric-simons","domain":"bolt.com"},{"id":10,"stmt":"A corporate card startup launched a product whose core promise was to help customers spend less money. Every financial services company said the model was backwards and would never work.","dec":"ship","co":"Ramp","yr":"2019","color":"#F6C000","expl":"Ramp became the fastest-growing SaaS and FinTech business in history, hitting $100M ARR in two years. CFOs chose them precisely because they were aligned on saving money, not extracting it.","pat":"Being on your customer's side of the table is a viable business model. Alignment on outcomes can be the moat.","url":"https://www.lennysnewsletter.com/p/velocity-over-everything-how-ramp","domain":"ramp.com"},{"id":11,"stmt":"A cybersecurity startup told investors they would reach $100M ARR within 18 months. The previous record was four years. Every investor they approached said it was impossible.","dec":"ship","co":"Wiz","yr":"2020","color":"#6B4FBB","expl":"Wiz hit $100M ARR in 18 months, the fastest in enterprise software history. Their CNAPP approach solved a problem every cloud security team had but nobody had addressed in a single product.","pat":"Category records exist until someone breaks them. Size of ambition is often a signal of quality of insight.","url":"https://www.lennysnewsletter.com/p/building-wiz-raaz-herzberg","domain":"wiz.io"},{"id":12,"stmt":"An AI presentation startup was told by investors it was 'the dumbest idea I've heard.' The founders pressed on anyway, building a tool that replaced traditional slide software.","dec":"ship","co":"Gamma","yr":"2022","color":"#7C3AED","expl":"Gamma reached $100M ARR. The 'dumb' idea was that AI could generate beautiful presentations from a simple prompt, removing a task that consumed hours of every knowledge worker's week.","pat":"The ideas investors dismiss are often the ones that replace existing behaviors rather than optimizing them.","url":"https://www.lennysnewsletter.com/p/how-50-people-built-a-profitable-ai-unicorn","domain":"gamma.app"},{"id":13,"stmt":"A project management tool launched with almost no customization options at all, in a market where every competitor competed on how many workflow options they offered.","dec":"ship","co":"Linear","yr":"2020","color":"#5E6AD2","expl":"Linear became the fastest-growing Jira alternative despite having a fraction of the features. Engineers loved the opinionated simplicity and speed. Less choice proved to be the product.","pat":"Removing options is a product decision. Opinionated defaults signal product taste and build trust with power users.","url":"https://www.lennysnewsletter.com/p/inside-linear-building-with-taste","domain":"linear.app"},{"id":14,"stmt":"Two co-founders bet their company on building professional design software in a web browser. Every design industry expert said it was technically impossible and would never replace desktop apps.","dec":"ship","co":"Figma","yr":"2013","color":"#F24E1E","expl":"Figma became the dominant design tool in the world. Adobe tried to acquire them for $20B. The impossible browser constraint forced a multiplayer-first architecture that became their biggest competitive advantage.","pat":"Technical constraints that seem like limitations can force architectural decisions that become core moats.","url":"https://www.lennysnewsletter.com/p/an-inside-look-at-figmas-unique-bottom","domain":"figma.com"},{"id":15,"stmt":"An AI coding tool decided to train and maintain their own custom AI models instead of just using existing APIs. Everyone said it was an expensive distraction from their core product.","dec":"ship","co":"Cursor","yr":"2024","color":"#1A1A1A","expl":"Cursor found that every magic moment in the product required a custom model. Training their own models became the source of their biggest quality advantages over competitors who only used base APIs.","pat":"When your product quality depends on a third-party model, your moat depends on them. Custom models can be where differentiation lives.","url":"https://www.lennysnewsletter.com/p/the-rise-of-cursor-michael-truell","domain":"cursor.com"},{"id":16,"stmt":"A tech giant banned all PowerPoint slides from executive strategy meetings and required all proposals to be written as 6-page narrative memos, read in silence at the start of every meeting.","dec":"ship","co":"Amazon","yr":"2004","color":"#FF9900","expl":"Jeff Bezos found that PowerPoint allowed people to hide weak thinking behind bullet points. Written memos forced clear reasoning. The ritual became core to Amazon's famously disciplined strategy culture.","pat":"The format of your decision-making ritual shapes the quality of your decisions. Making people write forces them to actually think.","url":"https://www.lennysnewsletter.com/p/unpacking-amazons-unique-ways-of","domain":"amazon.com"},{"id":17,"stmt":"A design tool startup decided to target non-designers as their primary customer, ignoring professional designers who were the obvious market for design software.","dec":"ship","co":"Canva","yr":"2013","color":"#7D2AE7","expl":"Canva became one of Australia's largest startups by serving the massive underserved market of people who needed to create visuals but had no design training. The 'amateur' market was far larger than the pro market.","pat":"The obvious customer is often not the biggest customer. Non-consumers who want a simpler version outnumber professionals who want a better one.","url":"https://www.lennysnewsletter.com/p/inside-canva-with-cameron-adams","domain":"canva.com"},{"id":18,"stmt":"A B2B messaging company shut down their popular enterprise product, which had tens of thousands of paying customers, to focus on a new product that hadn't proven itself yet.","dec":"skip","co":"Atlassian","yr":"2019","color":"#0052CC","expl":"The replacement product Stride also failed. Atlassian eventually discontinued it too and had to accept defeat in the messaging space entirely, handing the market to Slack. The shutdown created real customer pain for no gain.","pat":"Shutting down a revenue-generating product before the replacement is proven is a high-risk move. Customers remember the disruption.","url":"https://www.lennysnewsletter.com/p/building-0-to-1-inside-atlassian-tanguy-crusson","domain":"atlassian.com"},{"id":19,"stmt":"A social platform built a fact-checking system that specifically showed corrections from users who had previously disagreed with each other politically. Experts said polarized users would never agree on anything.","dec":"ship","co":"X / Twitter","yr":"2021","color":"#000000","expl":"Community Notes became one of the most respected misinformation tools in tech. Notes required agreement across political lines, making them far more credible than editorially curated fact-checks.","pat":"Cross-partisan agreement is harder to game than editorial curation. Designing for disagreement can produce more trustworthy signals than designing for consensus.","url":"https://www.lennysnewsletter.com/p/how-x-built-the-best-fact-checking-system-on-the-internet","domain":"x.com"},{"id":20,"stmt":"An e-commerce platform deleted all internal recurring meetings for their engineering teams, claiming that meetings were killing productivity. Other tech leaders said it would cause chaos.","dec":"ship","co":"Shopify","yr":"2023","color":"#96BF48","expl":"Shopify's 'chaos' experiment found that engineers shipped more and reported higher satisfaction. The company followed up with a 'meeting cost calculator' tool that showed employees the true cost of every calendar event.","pat":"Synchronous time is a tax on focus. Treating meetings as the default is a cultural choice, not an operational necessity.","url":"https://www.lennysnewsletter.com/p/how-shopify-builds-a-high-intensity-culture-farhan-thawar","domain":"shopify.com"},{"id":21,"stmt":"An HR software startup decided to also build IT management software in the same product, when every competitor, VC, and market analyst said HR and IT were two completely separate markets.","dec":"ship","co":"Rippling","yr":"2016","color":"#F5A623","expl":"Rippling's unified HR and IT platform became its core moat. Customers who ran both functions in one system had 10x higher retention than those using separate tools. The integration was the product.","pat":"Markets that analysts say are separate often have deep integration value waiting to be unlocked. The wedge that seems narrow can open a wide platform.","url":"https://www.lennysnewsletter.com/p/moving-fast-and-navigating-uncertainty","domain":"rippling.com"},{"id":22,"stmt":"A Brazilian fintech launched a credit card with no annual fees in a market where every major bank charged high fees and treated fees as non-negotiable industry standard.","dec":"ship","co":"Nubank","yr":"2013","color":"#8A05BE","expl":"Nubank became the most valuable bank in Latin America and one of the largest digital banks in the world. Brazilian consumers had been captive to abusive fee structures for decades. The simple promise of no fees created an enormous viral movement.","pat":"In markets with structurally bad incumbents, the bar to win can be 'just stop doing the thing everyone hates.' That can be enough.","url":"https://www.lennysnewsletter.com/p/be-fundamentally-different-jag-duggal","domain":"nubank.com.br"},{"id":23,"stmt":"An AI lab launched their flagship chatbot product completely free to anyone with an internet connection, walking away from potential revenue that competitors planned to charge for immediately.","dec":"ship","co":"OpenAI","yr":"2022","color":"#000000","expl":"ChatGPT became the fastest product to 100M users in history. The free launch seeded mass adoption and cultural penetration that no amount of paid marketing could have achieved. Paid tiers followed after the habit was formed.","pat":"When you are creating a new category, market education and adoption speed matter more than monetization. Get the habit first.","url":"https://www.lennysnewsletter.com/p/inside-chatgpt-nick-turley","domain":"openai.com"},{"id":24,"stmt":"A senior product leader left a prestigious PM role at a top consumer company to write a newsletter about product management. Colleagues said the move was career suicide.","dec":"ship","co":"Lenny's Newsletter","yr":"2019","color":"#D4622A","expl":"Lenny Rachitsky built one of the most influential newsletters in tech, with hundreds of thousands of paid subscribers. The move gave him more impact on product thinking than any PM role could have.","pat":"The career path that looks risky from inside a company often has far more leverage than staying on the conventional track.","url":"https://www.lennysnewsletter.com","domain":"lennysnewsletter.com"},{"id":25,"stmt":"A file storage startup gave users 500MB of free extra storage for every friend they referred, essentially paying for growth with the thing the growth would consume.","dec":"ship","co":"Dropbox","yr":"2009","color":"#0061FF","expl":"Dropbox grew 3,900% in 15 months after launching its referral program. The marginal cost of storage was far lower than the cost of equivalent paid acquisition. Storage given away as reward was their most efficient CAC ever.","pat":"When your product has marginal cost near zero, giving more of it away as an incentive is often the cheapest customer acquisition available.","url":"https://www.lennysnewsletter.com/p/behind-the-founder-drew-houston-dropbox","domain":"dropbox.com"},{"id":26,"stmt":"A consumer hardware startup spent nearly two years perfecting product quality before launch, generating a 200,000-person waitlist with nothing but a waitlist page and no product demo.","dec":"ship","co":"Superhuman","yr":"2017","color":"#FF6B35","expl":"Superhuman's long waitlist created massive perceived exclusivity. By the time users got access, they already believed it was worth waiting for. The manufactured scarcity primed people to find value they might otherwise have dismissed.","pat":"Controlled scarcity changes the user's frame before they touch the product. People who had to wait are already predisposed to justify that wait.","url":"https://www.lennysnewsletter.com/p/superhumans-secret-to-success-rahul-vohra","domain":"superhuman.com"},{"id":27,"stmt":"A productivity startup spent three years rebuilding their product entirely from scratch, going offline completely during the rebuild and watching their user base shrink dramatically.","dec":"ship","co":"Notion","yr":"2016","color":"#37352F","expl":"Notion rebuilt from scratch to get the right technical foundation. The rebuilt product found explosive PMF after years of quiet. By 2021 they reached a $10B valuation. The rebuild that seemed catastrophic was actually the condition for their eventual scale.","pat":"There are moments when the right move is to tear it down and restart. Technical debt compounds like financial debt, and sometimes the only way out is through.","url":"https://www.lennysnewsletter.com/p/inside-notion-ivan-zhao","domain":"notion.so"},{"id":28,"stmt":"A project management tool launched with no mobile app at all in an era where mobile-first was considered mandatory for any new software product.","dec":"ship","co":"Linear","yr":"2020","color":"#5E6AD2","expl":"Linear's desktop-and-web-first strategy let them build a product with genuine keyboard-driven speed that mobile-first tools couldn't match. Engineers loved it. The mobile app came later once the core experience was locked in.","pat":"Building for the platform where your users do their deepest work first beats building for all platforms simultaneously and doing all of them poorly.","url":"https://www.lennysnewsletter.com/p/inside-linear-building-with-taste","domain":"linear.app"},{"id":29,"stmt":"A consumer app introduced a paid subscription tier at $9.99/month while offering a free version that covered most of the same use cases. Analysts predicted the paid tier would get almost no takers.","dec":"ship","co":"Duolingo","yr":"2018","color":"#58CC02","expl":"Duolingo Plus converted far better than analyst predictions. Users who were engaged enough to hit limits on the free tier were willing to pay to remove friction. The conversion rate validated a freemium model that most edtech companies had abandoned.","pat":"Freemium conversion is driven by engagement depth, not feature gating. If users are hitting limits, some will always pay to remove them.","url":"https://www.lennysnewsletter.com/p/behind-the-product-duolingo-streaks","domain":"duolingo.com"},{"id":30,"stmt":"A software tool company introduced a system that penalized engineers for keeping code over one hour old. If they could not finish in an hour, they were required to delete all the code and start again.","dec":"ship","co":"Shopify","yr":"2020","color":"#96BF48","expl":"Shopify's extreme code deletion rule forced engineers to design with clarity first. If a feature could not be articulated clearly enough to code in an hour, the design was wrong. The constraint dramatically improved code architecture.","pat":"Extreme time constraints can be a design tool. If you cannot ship it in the constraint, the real problem is usually that you do not understand it well enough yet.","url":"https://www.lennysnewsletter.com/p/how-shopify-builds-a-high-intensity-culture-farhan-thawar","domain":"shopify.com"},{"id":31,"stmt":"A B2B software company replaced all annual performance reviews with continuous weekly one-on-ones and eliminated year-end bonuses entirely. HR consultants called it reckless.","dec":"ship","co":"Shopify","yr":"2019","color":"#96BF48","expl":"Shopify found that continuous feedback loops outperformed annual review cycles for retention and growth. Employees who got weekly feedback adjusted their behavior in real-time rather than waiting 12 months to learn what had not been working.","pat":"The feedback loop speed shapes the learning speed. Annual reviews optimize for paperwork. Weekly conversations optimize for growth.","url":"https://www.lennysnewsletter.com/p/how-shopify-builds-a-high-intensity-culture-farhan-thawar","domain":"shopify.com"},{"id":32,"stmt":"A venture-funded startup launched a product that intentionally slowed down as users got better at it, making the learning experience harder over time instead of easier.","dec":"ship","co":"Duolingo","yr":"2015","color":"#58CC02","expl":"Duolingo's spaced repetition system deliberately introduced difficulty at the moment when retention begins to decay. The harder the experience became as users improved, the better the long-term retention of the language.","pat":"Products that get harder as users improve create more durable engagement than products that get easier. Challenge is not friction. It is the point.","url":"https://www.lennysnewsletter.com/p/behind-the-product-duolingo-streaks","domain":"duolingo.com"},{"id":33,"stmt":"A company publicly announced it was not going to add any new features to its product for a full year and instead would spend all development time reducing technical debt.","dec":"ship","co":"Intercom","yr":"2018","color":"#1F8FFF","expl":"Intercom's product quality improved dramatically after their technical debt investment. Customers noticed the speed and reliability improvements. The counterintuitive public commitment also built trust and press coverage about their engineering discipline.","pat":"Publicly committing to slow down feature velocity to fix foundations can be a competitive differentiator. Customers who have suffered from tech debt elsewhere notice quality.","url":"https://www.lennysnewsletter.com/p/what-ai-means-for-your-product-strategy","domain":"intercom.com"},{"id":34,"stmt":"An AI startup decided to focus their product entirely on a single use case — coding — rather than building a general assistant that could do everything.","dec":"ship","co":"Cursor","yr":"2022","color":"#1A1A1A","expl":"Cursor's coding-specific focus allowed them to build deeply integrated features that general AI assistants couldn't match. By going narrow, they became the gold standard in their category rather than a mediocre version of a general tool.","pat":"Depth in one vertical almost always beats breadth across many when your target user's most important job is the vertical you serve.","url":"https://www.lennysnewsletter.com/p/the-rise-of-cursor-michael-truell","domain":"cursor.com"},{"id":35,"stmt":"A founder pitched over 100 investors and was rejected by every single one. Instead of pivoting, she used each rejection to strengthen her pitch deck, telling investors their market estimates were simply wrong.","dec":"ship","co":"Canva","yr":"2012","color":"#7D2AE7","expl":"Melanie Perkins kept pitching after 100+ rejections, eventually raising from a kite-surfing connection in Hawaii. Canva went on to reach $42B valuation with 240M monthly users and 8 consecutive years of profitability.","pat":"Conviction in your market vision, when it contradicts the consensus, is not stubbornness. Sometimes you are right and the room is wrong.","url":"https://www.lennysnewsletter.com/p/the-making-of-canva","domain":"canva.com"},{"id":36,"stmt":"A design startup's engineering team spent two full years rewriting their codebase from scratch, unable to ship a single new feature to customers the entire time. Competitors kept shipping. The team stayed the course.","dec":"ship","co":"Canva","yr":"2014","color":"#7D2AE7","expl":"Canva's technical rewrite was painful but necessary. The rebuilt platform became the foundation for everything that followed. Today Canva generates $3B+ ARR. The two silent years made the next decade possible.","pat":"A product that cannot scale technically cannot win at scale. Rebuilding a flawed foundation while falling behind is sometimes the most important thing you can do.","url":"https://www.lennysnewsletter.com/p/the-making-of-canva","domain":"canva.com"},{"id":37,"stmt":"A software company with fewer than 80 employees generating tens of millions in annual profit deliberately chose never to raise venture capital, hire a board, or sell the company. Ever.","dec":"ship","co":"37signals","yr":"2001","color":"#5BC0DE","expl":"Jason Fried built 37signals — the maker of Basecamp and HEY — as a calm, profitable, independent company. No investors, no boss above him. He argued this was a strategic choice, not a failure to raise.","pat":"Refusing to raise is a strategy, not a failure mode. Profitability buys independence. Independence buys the ability to make product decisions without external pressure.","url":"https://www.lennysnewsletter.com/p/jason-fried-challenges-your-thinking","domain":"37signals.com"},{"id":38,"stmt":"A team at a language learning app spent months copying a mechanic from a casual mobile game into their product. After launch, the result was completely neutral. Zero retention improvement. The team nearly disbanded.","dec":"skip","co":"Duolingo","yr":"2018","color":"#58CC02","expl":"The Gardenscapes moves counter worked because the game required strategy. Duolingo questions don't — you either know the answer or you don't. The feature added boring friction. Adapting without understanding why something works in its original context is a common and expensive mistake.","pat":"When borrowing mechanics from other products, ask why it works there before asking whether it will work here. Context changes everything.","url":"https://www.lennysnewsletter.com/p/how-duolingo-reignited-user-growth","domain":"duolingo.com"},{"id":39,"stmt":"A language learning app built a referral program offering a free month of their premium subscription to users who referred friends, inspired directly by a ride-sharing app's referral growth engine. They launched it company-wide.","dec":"skip","co":"Duolingo","yr":"2018","color":"#58CC02","expl":"Uber's referral worked because rides are recurring and the reward was a free ride. Duolingo's best users already had premium. The reward excluded its own most likely evangelists. New users grew only 3% — not the breakthrough they needed.","pat":"A successful growth mechanic from another company is not a recipe. You have to understand why it worked there before you can know whether it will work for you.","url":"https://www.lennysnewsletter.com/p/how-duolingo-reignited-user-growth","domain":"duolingo.com"},{"id":40,"stmt":"A language learning app rebuilt their leaderboard system from scratch, based on mechanics from a mobile farming game, automatically matching strangers against each other rather than friends. Users hadn't asked for it.","dec":"ship","co":"Duolingo","yr":"2019","color":"#58CC02","expl":"The new leaderboard drove a 17% increase in overall learning time and tripled the number of highly engaged learners within weeks. It became the Retention Team's first major breakthrough after two prior failures.","pat":"Competing against strangers at the same level creates urgency that competing against friends cannot. Proximity of skill matters more than proximity of relationship.","url":"https://www.lennysnewsletter.com/p/how-duolingo-reignited-user-growth","domain":"duolingo.com"},{"id":41,"stmt":"A company's CEO told the push notification team they could optimize everything — timing, copy, images — but could never increase the number of notifications sent without CEO approval.","dec":"ship","co":"Duolingo","yr":"2019","color":"#58CC02","expl":"The rule came from watching Groupon A/B test their email channel to death. Hundreds of small wins from optimizing within the constraint drove substantial DAU improvements over four years without destroying the channel.","pat":"Aggressive A/B testing on notification channels can permanently destroy them as users opt out. Protect the channel first, optimize within it second.","url":"https://www.lennysnewsletter.com/p/how-duolingo-reignited-user-growth","domain":"duolingo.com"},{"id":42,"stmt":"An AI coding startup abandoned a profitable, working infrastructure business after raising $28M, telling investors they were pivoting entirely to a consumer AI code editor with no proven demand.","dec":"ship","co":"Windsurf","yr":"2023","color":"#1A6B5C","expl":"Varun Mohan and team pivoted from Codeium's infrastructure business to build Windsurf, an AI IDE. The bet-the-company moment worked. Windsurf hit 1 million developers in four months and became Cursor's main competitor.","pat":"When your core insight changes — that your existing market will be commoditized by a new technology — the right move may be to abandon what is working to chase what will matter.","url":"https://www.lennysnewsletter.com/p/the-untold-story-of-windsurf-varun-mohan","domain":"windsurf.com"},{"id":43,"stmt":"A product lead at a social media platform treated every long-held assumption about the product — no editing posts, no long-form, no video — as a built-in roadmap of things worth testing, not rules to respect.","dec":"ship","co":"Twitter","yr":"2020","color":"#1DA1F2","expl":"Kayvon Beykpour called sacred cows 'a built-in roadmap.' His team shipped Super Follows, Communities, Spaces, newsletters, and live video in rapid succession — more product change in two years than the prior decade.","pat":"The strongest signal of what to build next is what everyone believes you are not allowed to change. Inherited constraints are not constraints unless you accept them.","url":"https://www.lennysnewsletter.com/p/twitters-former-head-of-product-kayvon-beykpour","domain":"twitter.com"},{"id":44,"stmt":"A live video startup onboarded every single beta user personally during its first months, calling them on the phone, walking them through the app one at a time, before any public launch.","dec":"ship","co":"Periscope","yr":"2015","color":"#1DA1F2","expl":"Kayvon Beykpour personally called every Periscope beta user. The unscalable practice created deep loyalty in early adopters who became the product's most vocal advocates. Periscope inspired Instagram Live, TikTok Live, and Facebook Live.","pat":"Personal onboarding at launch is not a waste of time. It is the fastest way to find what matters to real users and create the advocates who spread the product for you.","url":"https://www.lennysnewsletter.com/p/twitters-former-head-of-product-kayvon-beykpour","domain":"periscope.tv"},{"id":45,"stmt":"A well-loved AI news app that had been building loyal users for two years was shut down by its founders despite users adoring it, because they concluded it took ten units of effort for every one unit of output.","dec":"ship","co":"Artifact","yr":"2024","color":"#FF6600","expl":"Mike Krieger and Kevin Systrom shut down Artifact when they saw it couldn't grow organically. Despite users loving it, headwinds from deteriorating mobile web, poor organic spread, and full remote working made further investment the wrong use of time.","pat":"Shutting down a product people love, when the energy is not in the system, is not failure. It is recognising that love without growth is a cul-de-sac.","url":"https://www.lennysnewsletter.com/p/anthropics-cpo-heres-what-comes-next","domain":"artifact.news"},{"id":46,"stmt":"An engineering manager at a ride-sharing company left a $330K total comp job to write a newsletter about software engineering with no guarantee of income. His family thought he was making a mistake.","dec":"ship","co":"The Pragmatic Engineer","yr":"2021","color":"#FF4500","expl":"Gergely Orosz built The Pragmatic Engineer into the number one technology newsletter on Substack within one year of going independent. He now earns more than he did at Uber, with no theoretical cap.","pat":"A job with a ceiling trades security for limitation. Leaving a well-paid role to build something with compounding upside is a legitimate career strategy, not recklessness.","url":"https://www.lennysnewsletter.com/p/leaving-big-tech-to-build-the-1-technology","domain":"pragmaticengineer.com"},{"id":47,"stmt":"A podcast hosting startup secretly hired college interns to manually create Apple Podcast accounts and submit podcasts one by one, making what was grueling manual work feel like magic automation to users.","dec":"ship","co":"Anchor","yr":"2016","color":"#1DB954","expl":"Anchor's fake-automation trick gave it a massive distribution advantage over competitors. Users believed Anchor had a secret deal with Apple. By the time Spotify acquired Anchor, it powered over 75% of all new podcasts created worldwide.","pat":"If you can fake the experience before you can build it, the signal you get from real users is worth more than any prototype test. Do things that don't scale until you prove the thing is worth scaling.","url":"https://www.lennysnewsletter.com/p/building-anchor-selling-to-spotify","domain":"anchor.fm"},{"id":48,"stmt":"A consumer AI startup set a company engineering goal that every engineer must ship one marketable product feature every week. Quality reviewers said the pace would destroy the product.","dec":"ship","co":"Captions","yr":"2023","color":"#FF3B30","expl":"Captions built one of the most successful consumer AI products in the world. Their weekly shipping cadence kept the product top of mind in a fast-moving AI market and forced ruthless scope cutting rather than timeline extension.","pat":"Compressing shipping cycles forces prioritization. When you have to ship something weekly, you stop agonizing over what to build and start executing on the most important thing.","url":"https://www.lennysnewsletter.com/p/how-to-win-in-the-ai-era-gaurav-misra","domain":"captions.ai"},{"id":49,"stmt":"A startup built a product in two days and then ignored it completely for 18 months while chasing other ideas. During those 18 months of zero investment, it grew to 500,000 users entirely on its own.","dec":"ship","co":"Captions","yr":"2021","color":"#FF3B30","expl":"Captions' AI video tool grew to half a million users with no updates, no marketing, and no support. When the team finally noticed and refocused on it, 'what looked like a vertical line became a horizontal line.' The ignored product became the company.","pat":"Organic growth with no investment is the strongest possible signal. If something is growing without you, stop ignoring it and go water it.","url":"https://www.lennysnewsletter.com/p/how-to-win-in-the-ai-era-gaurav-misra","domain":"captions.ai"},{"id":50,"stmt":"A consumer app founder noticed the number one app in the US App Store was in Arabic, a language almost no American reads, and decided that was the best business signal he had ever seen.","dec":"ship","co":"TBH","yr":"2017","color":"#6B47ED","expl":"Nikita Bier read the Arabic app's latent demand signal correctly. He launched TBH — an anonymous positive compliment app for teens — and it hit number one in the US in six days, selling to Facebook for over $30M.","pat":"Your best market research is the list of what people are already doing imperfectly. An Arabic app dominating English-speaking users means a job is being done very badly by available tools.","url":"https://www.lennysnewsletter.com/p/how-to-consistently-go-viral-nikita-bier","domain":"tbh.me"},{"id":51,"stmt":"A two-time unicorn founder built every one of his companies starting from a painful problem rather than a product idea, and told every investor and employee to fall in love with that problem first.","dec":"ship","co":"Waze","yr":"2009","color":"#00BCD4","expl":"Uri Levine co-founded Waze, which Google acquired for $1.3B, by obsessing over the problem of broken navigation and traffic data. His philosophy: if you love the problem enough, the right solution eventually reveals itself through iteration.","pat":"Solutions age. Problems persist. A team in love with the problem will keep iterating past failed solutions. A team in love with its solution will defend it past the point of usefulness.","url":"https://www.lennysnewsletter.com/p/lessons-from-uri-levine","domain":"waze.com"},{"id":52,"stmt":"An AI company decided to focus its consumer product strategy on builders, tinkerers, and developers rather than chasing the mainstream consumer mindshare that every analyst said it needed to compete for.","dec":"ship","co":"Anthropic","yr":"2024","color":"#D4622A","expl":"Mike Krieger made the deliberate choice to embrace Anthropic's developer and builder identity rather than imitating OpenAI's consumer playbook. The strategy leaned into the fact that builders already loved Claude and built the most successful AI products on top of it.","pat":"Trying to beat a competitor at their own game with their own positioning is rarely the right move. Find where you have genuine affinity and double down on that.","url":"https://www.lennysnewsletter.com/p/anthropics-cpo-heres-what-comes-next","domain":"anthropic.com"},{"id":53,"stmt":"A startup shipped a deliberately ugly, broken-looking feature to users, certain that users would hate it. Nothing happened. Nobody cared. The team was shocked.","dec":"ship","co":"IMVU","yr":"2004","color":"#FF6B35","expl":"Eric Ries shipped an embarrassingly bad feature at IMVU expecting disaster. The total non-reaction was the founding insight of Lean Startup: most of what engineers worry users will hate, users don't even notice. Validated learning beats theorizing.","pat":"The fear of shipping something imperfect is almost always bigger than the actual consequences of shipping it. Users notice far less than builders imagine.","url":"https://www.lennysnewsletter.com/p/reflections-on-a-movement-eric-ries","domain":"imvu.com"},{"id":54,"stmt":"A startup running low on runway decided to scrap their entire product and redesign it from scratch rather than iterating, even though they had paying customers and working software.","dec":"ship","co":"Gamma","yr":"2022","color":"#7C3AED","expl":"Grant Lee described it as a bet-the-company moment. Gamma threw out what was working to rebuild around AI generation. On the other side it 'felt so different.' The rebuilt product reached $100M ARR with 50 people.","pat":"When an insight tells you the current product is the wrong shape entirely, iteration will never get you to the right shape. Sometimes the only way forward is a clean break.","url":"https://www.lennysnewsletter.com/p/how-50-people-built-a-profitable-ai-unicorn","domain":"gamma.app"},{"id":55,"stmt":"The CEO of an e-commerce platform deliberately banned KPIs and metrics from core product teams. All roadmap decisions were driven by taste, intuition, and a 100-year company vision — not quarterly targets.","dec":"ship","co":"Shopify","yr":"2020","color":"#96BF48","expl":"Tobi Lütke argued that metrics are a proxy for what you actually want — and that a 100-year horizon makes many short-term proxies irrelevant. Core teams optimize toward a vision, not a dashboard. Shopify became a $130B business powering 10% of US e-commerce.","pat":"Metrics are a cage when the goal can be stated more directly. A long enough time horizon makes certain short-term measures not just useless but harmful. Build toward the mission, not toward the measurement of the mission.","url":"https://www.lennysnewsletter.com/p/tobi-lutkes-leadership-playbook","domain":"shopify.com"},{"id":56,"stmt":"An AI startup hit $4M ARR in its first four weeks and $10M ARR in its first two months — with a team of just 15 people. Leadership refused to scale headcount even as demand exploded.","dec":"ship","co":"Lovable","yr":"2025","color":"#FF6B6B","expl":"Anton Osika built Lovable as an AI software engineer that turns English into working products. The 15-person constraint forced ruthless prioritisation and preserved the speed that made the growth possible. Lovable became Europe's fastest-growing startup ever.","pat":"Headcount is a leading indicator of bureaucracy, not output. When something is growing fast with a tiny team, adding people to go faster often makes you slower. Stay small as long as the product still ships.","url":"https://www.lennysnewsletter.com/p/building-lovable-anton-osika","domain":"lovable.dev"},{"id":57,"stmt":"A social network attempted to launch a global cryptocurrency that would let users send money internationally for free via its messaging app. Regulators across multiple governments blocked it before a single user could send a dollar.","dec":"skip","co":"Facebook","yr":"2019","color":"#1877F2","expl":"Kevin Weil called Libra the biggest disappointment of his career. He believed — and still believes — the world would be better if it existed. A technically sound product with genuine user value was killed not by the market but by political opposition. Sometimes perfect execution is not enough.","pat":"Regulatory risk is as real as technical risk. Building something that requires governments not to oppose you is a product bet, not just a compliance problem. Model the political environment as carefully as the user environment.","url":"https://www.lennysnewsletter.com/p/kevin-weil-open-ai","domain":"facebook.com"},{"id":58,"stmt":"A search giant's photo product launched with free unlimited photo storage for life, directly nuking a file storage startup's consumer business model. The file storage startup had just shut down two beloved consumer products to focus on productivity. The timing looked catastrophic.","dec":"ship","co":"Dropbox","yr":"2015","color":"#0061FF","expl":"Drew Houston killed Carousel and Mailbox to go all-in on work productivity — right as Google eliminated Dropbox's consumer pricing advantage. The internal narrative collapsed. Years later, Dropbox emerged as a profitable public company on exactly that productivity bet.","pat":"Cutting beloved products to focus is always painful and always controversial. The worst time to make such a call is during an external attack — but sometimes the external pressure is the forcing function that makes the hard call possible.","url":"https://www.lennysnewsletter.com/p/behind-the-founder-drew-houston-dropbox","domain":"dropbox.com"},{"id":59,"stmt":"An engineering leader gathered 100 engineers for a 15-minute session and had everyone push AI-generated code simultaneously — producing 75 merged pull requests. The goal was to change the team's mental model about what was possible.","dec":"ship","co":"Coinbase","yr":"2024","color":"#0052FF","expl":"Chintan Turakhia at Coinbase reduced PR review times from 150 hours to 15 hours through AI tooling. The collective speed run transformed how 1,000 engineers thought about their own capabilities. Showing beats telling — the single shared session accomplished what months of individual encouragement could not.","pat":"The fastest way to change a team's mental model about what is possible is to make them experience the possibility together. A shared demonstration is more persuasive than any number of individual encouragements or mandates.","url":"https://www.lennysnewsletter.com/p/how-coinbase-scaled-ai-to-1000-engineers","domain":"coinbase.com"},{"id":60,"stmt":"The founder of the software powering 43% of the internet publicly went to war with a major hosting company using his software's brand — despite instant, widespread public backlash that turned him into what he called an 'internet villain'.","dec":"ship","co":"WordPress","yr":"2024","color":"#21759B","expl":"Matt Mullenweg stood up to WP Engine because he believed letting companies dilute open-source freely would harm the entire ecosystem. He was willing to burn years of goodwill to protect the foundational rules. As he put it: a lie gets around the world seven times before the truth gets out of bed.","pat":"Standing up for the rules of your ecosystem, even when it makes you temporarily unpopular, is sometimes the only way to preserve what made that ecosystem worth building on. Short-term reputation cost is not the same as long-term strategic cost.","url":"https://www.lennysnewsletter.com/p/the-creator-of-wordpress-opens-up-matt-mullenweg","domain":"wordpress.com"},{"id":61,"stmt":"The CEO of a developer tools company argued that product taste is not a natural talent but a learnable skill — and mandated that his entire team track and increase their 'exposure hours' to great products as a formal practice.","dec":"ship","co":"Vercel","yr":"2025","color":"#000000","expl":"Guillermo Rauch built v0 with the goal of expanding the global pool of builders from 5 million developers to 100 million people. His core insight: taste develops through deliberate exposure, not through natural aptitude. Teams that systematically increase exposure to excellent products ship better products.","pat":"Taste is not a fixed trait. Teams that treat taste development as a practice — measured, tracked, and systematically built — produce better products over time than teams who assume the best designers were simply born that way.","url":"https://www.lennysnewsletter.com/p/everyones-an-engineer-now-guillermo-rauch","domain":"vercel.com"},{"id":62,"stmt":"A product team built their own version of a feature that a competitor had invented, shipped it into a product with far larger distribution, and watched it quickly surpass the original despite widespread criticism that it was derivative.","dec":"ship","co":"Instagram","yr":"2016","color":"#E1306C","expl":"Robby Stein led the decision to build Instagram Stories, a direct copy of Snapchat Stories. Instagram Stories quickly surpassed Snapchat in daily active users. Stein later applied the same relentless improvement philosophy to building Google's AI Overviews despite public backlash.","pat":"Building a better-distributed version of something that exists is product strategy, not plagiarism. The original inventor does not own the concept. Execution and distribution determine who wins in the long run.","url":"https://www.lennysnewsletter.com/p/how-google-built-ai-mode-in-under-a-year","domain":"instagram.com"},{"id":63,"stmt":"A startup CEO took his company public with only $2 million in revenue during the dot-com crash. Everyone called it 'the IPO from hell.' He did it anyway because the only alternative was bankruptcy.","dec":"ship","co":"Loudcloud","yr":"2001","color":"#6600CC","expl":"Ben Horowitz took Loudcloud public during the worst market conditions in a generation. The IPO raised the capital needed to survive and buy time for the pivot that eventually sold the company for $1.6B. He later co-founded a16z, which backed companies worth hundreds of billions. The embarrassing IPO made all of it possible.","pat":"When the choice is between a bad option and a worse option, the bad option is the right one. An embarrassing IPO is better than a dignified shutdown. Great leaders act decisively with equally bad choices rather than waiting for a good one.","url":"https://www.lennysnewsletter.com/p/46b-of-hard-truths-from-ben-horowitz","domain":"loudcloud.com"},{"id":64,"stmt":"An entrepreneur built a holding company with over $300M in annual revenue owning 35+ internet brands — including a coffee maker and a design community — without raising a single dollar of venture capital across 75+ businesses.","dec":"ship","co":"Tiny","yr":"2010","color":"#2D6A4F","expl":"Andrew Wilkinson started as a teenage barista and built Tiny entirely from reinvested profits. His thesis: the only difference between bootstrapping and VC is tolerance for burning money. Businesses with natural moats and patient capital can build massive value without giving up equity or control.","pat":"Venture capital is one model. It is not the only model. Businesses built on profit-funded growth must have better unit economics from day one — which turns out to be a feature, not a bug.","url":"https://www.lennysnewsletter.com/p/ive-run-75-businesses-andrew-wilkinson","domain":"tiny.com"},{"id":65,"stmt":"The CEO of a coding platform predicted that within five years someone will run a billion-dollar company with zero employees — AI handling support, development, and operations — and built his platform to make that possible.","dec":"ship","co":"Replit","yr":"2024","color":"#F26207","expl":"Amjad Masad built Replit with 34 million users by making software creation accessible to anyone. His thesis: the engineering bottleneck is disappearing, so the new constraint is idea generation — not execution. Whoever internalises this shift first gains a structural advantage over teams still optimising for engineering throughput.","pat":"The constraint on product development is shifting from 'who can build this?' to 'who knows what to build?' Teams that adapt to this new bottleneck before their competitors will dominate the next decade.","url":"https://www.lennysnewsletter.com/p/behind-the-product-replit-amjad-masad","domain":"replit.com"},{"id":66,"stmt":"The Chief Product Officer of a major software company argued that any product team not using AI to prototype is doing it wrong — and that the real danger is not AI replacing products but competitors using AI to build something so much better yours becomes irrelevant.","dec":"ship","co":"Microsoft","yr":"2025","color":"#00A4EF","expl":"Aparna Chennapragada pushed Microsoft product teams to treat AI prototyping as a core skill, not an optional tool. Her key insight: the biggest mistake is using AI to automate what already exists rather than to reimagine the product from scratch. Incremental improvement is safe and insufficient.","pat":"Using AI to make your existing product slightly better is the wrong question. The right question is: what product would you build if you were starting from scratch today with these tools? That product is your real competitor.","url":"https://www.lennysnewsletter.com/p/microsoft-cpo-on-ai","domain":"microsoft.com"},{"id":67,"stmt":"A project management company implemented radical transparency as a core operating principle — sharing financial data, OKRs, and strategic decisions openly across the entire company, including junior employees.","dec":"ship","co":"Monday.com","yr":"2023","color":"#FF3750","expl":"Daniel Lereya found that radical transparency at Monday.com dramatically reduced misalignment and second-guessing at every level. When people understand the real 'why' behind decisions, they make better local decisions without escalating. Information hoarding creates slow, bureaucratic companies. Openness is a speed strategy.","pat":"Transparency is not just a value. When employees understand the company's actual financial position and strategic priorities, they make better autonomous decisions. The cost of information hoarding is measured in slow, poorly-informed decisions compounding across thousands of interactions daily.","url":"https://www.lennysnewsletter.com/p/inside-mondays-transformation-daniel-lereya","domain":"monday.com"},{"id":68,"stmt":"A social network's longest-serving executive — still there 20 years after joining as employee #29 — insisted that every complex project must have a single canonical document that anyone in the company can find in under 30 seconds. No exceptions.","dec":"ship","co":"Meta","yr":"2015","color":"#1877F2","expl":"Naomi Gleit, who has worked alongside Zuckerberg for two decades, found that most cross-functional problems trace back to information fragmentation. Five people giving five different answers about the same project is a systems failure, not a people failure. One known, authoritative doc eliminates a massive category of coordination overhead.","pat":"Most coordination problems in large teams are documentation problems. When the authoritative source of truth is known and accessible to everyone, trust increases, meetings decrease, and people make better decisions without management review.","url":"https://www.lennysnewsletter.com/p/metas-head-of-product-naomi-gleit","domain":"meta.com"},{"id":69,"stmt":"A fintech worth $45B told its product managers they were expected to operate as 'local CEOs' — owning P&L, strategy, and execution — and hired for raw intellectual horsepower over years of domain experience.","dec":"ship","co":"Revolut","yr":"2022","color":"#0075EB","expl":"Dmitry Zlokazov at Revolut found that the local CEO model attracted a fundamentally different type of ambition than traditional PM roles. Speed of learning mattered more than experience. The scope of autonomy you offer a role determines who applies for it — and raises the ceiling of what the team can achieve.","pat":"Role design is talent strategy. Giving PMs genuine P&L ownership attracts people who want to build businesses, not just ship features. The ceiling of a product team is set by the scope of responsibility you give them.","url":"https://www.lennysnewsletter.com/p/how-revolut-trains-world-class-product-managers","domain":"revolut.com"},{"id":70,"stmt":"A software company deployed engineers directly inside enterprise client organisations for months at a time — living on-site, learning workflows firsthand — instead of building remotely from requirements documents.","dec":"ship","co":"Palantir","yr":"2008","color":"#1B1B1B","expl":"Palantir's forward-deployed engineer model was expensive and hard to scale, but it produced an unusually deep understanding of enterprise problems that remote teams simply cannot replicate. The model also became a founder factory — many alumni went on to build significant companies of their own.","pat":"The distance between builder and user is inversely correlated with product quality. The most accurate requirements document is irrelevant compared to six months of working inside the customer's actual operation. Immersion beats specification.","url":"https://www.lennysnewsletter.com/p/inside-palantir-nabeel-qureshi","domain":"palantir.com"},{"id":71,"stmt":"The first marketing hire at a payments infrastructure company decided not to follow any existing B2B marketing playbook and focused entirely on making developers so successful with the product that the product marketed itself.","dec":"ship","co":"Stripe","yr":"2013","color":"#6772E5","expl":"Krithika Shankarraman built Stripe's marketing function from scratch with an engineering mindset. Her conclusion: the most successful companies don't follow existing playbooks — they create new ones specific to their product and customer. At Stripe, a developer who succeeded told ten colleagues. No campaign competes with that.","pat":"In developer tools, the product IS the marketing. Success spreads through developers telling other developers. Building for user success before building for awareness is not modesty — it is the highest-leverage marketing strategy available.","url":"https://www.lennysnewsletter.com/p/growth-tactics-from-openai-and-stripes-first-marketer","domain":"stripe.com"},{"id":72,"stmt":"A hardware and software company deliberately built its product team culture around the ability to 'take a punch' — treating resilience under setbacks as the most important team asset, more important than raw talent.","dec":"ship","co":"Whoop","yr":"2023","color":"#00C8FF","expl":"Hilary Gridley at Whoop found that product velocity depended less on talent and more on a team's ability to absorb failure and keep moving. Teams that crumbled under adversity were slower overall than moderately talented teams who were resilient. Psychological safety turned out to be a product engineering decision.","pat":"A team that handles failure well ships more than a more talented team that cannot. Resilience is a product team's most underrated competitive advantage. Building it deliberately is as important as hiring for skill.","url":"https://www.lennysnewsletter.com/p/how-to-build-a-team-that-can-take-a-punch","domain":"whoop.com"},{"id":73,"stmt":"A product leader who had worked at a major search company moved to a crypto exchange where decisions had to be made ten times faster than anywhere he had worked before — and found that extreme speed constraints forced better, not worse, decision-making.","dec":"ship","co":"Binance","yr":"2022","color":"#F3BA2F","expl":"Mayur Kamat brought lessons from Binance, N26, and Google, finding that radically different constraints revealed which product practices were genuinely universal and which were just habits of comfortable, slow environments. The best way to test any principle is to take it somewhere it has no room to hide.","pat":"Comfort-zone product practices are often process theater rather than genuine principles. Imposing extreme speed or resource constraints forces a team to discover what actually matters and discard everything that was just habit.","url":"https://www.lennysnewsletter.com/p/unorthodox-product-lessons-from-n26-and-more","domain":"binance.com"},{"id":74,"stmt":"A designer with 35 years of experience across a consumer electronics company, an entertainment giant, and a social discovery platform argued that the single most critical product skill is not design or engineering — it is the ability to describe clearly what you are trying to make before anyone starts making it.","dec":"ship","co":"Apple","yr":"2025","color":"#A2AAAD","expl":"Bob Baxley distilled decades of product design wisdom into a single core principle: most products fail not because they were executed badly but because they were never described specifically enough. A vivid, detailed description of the intended experience is the most powerful alignment tool a product team can have.","pat":"You cannot build what you cannot describe. Time spent articulating exactly what success looks, feels, and works like — before a single line of code is written — is not lost time. It is the leverage point for everything that follows.","url":"https://www.lennysnewsletter.com/p/35-years-of-product-design-wisdom-bob-baxley","domain":"apple.com"},{"id":75,"stmt":"A search giant deployed over 1,000 engineers to build a social network embedded inside its most-used products — email, video, and maps — making sign-up nearly automatic for existing users. Executives called it the company's single highest priority.","dec":"skip","co":"Google","yr":"2011","color":"#4285F4","expl":"Google+ was wired into Gmail, YouTube, and Maps, creating over a billion forced accounts but almost no organic engagement. After eight years — and a high-profile data breach — the network was shut down entirely in 2019. A thousand engineers, a decade of effort, zero lasting social graph.","pat":"Mandatory distribution through existing products cannot manufacture social engagement. Users who are enrolled are not users who care.","domain":"google.com"},{"id":76,"stmt":"Airbnb launched Airbnb Plus — a certified premium tier requiring professional in-home inspections to guarantee quality standards","dec":"skip","co":"Airbnb","yr":"2018","color":"#FF5A5F","expl":"Airbnb sent inspectors to certify properties one by one. The unit economics never worked — the cost of running inspections at scale made the tier unviable. Jiaona Zhang, who led the project, later called it one of her biggest product failures.","pat":"Premium tiers that depend on costly per-unit human operations rarely survive contact with scale.","url":"https://www.lennysnewsletter.com/p/failure","domain":"airbnb.com"},{"id":77,"stmt":"Duolingo shipped a live social feature called Dual Duels, letting two users race through lessons against each other in real time","dec":"skip","co":"Duolingo","yr":"2017","color":"#58CC02","expl":"Dual Duels was built and launched, but almost nobody used it. The feature was pulled. Gina Gotthilf, who led growth at Duolingo, cited it as a classic example of a feature that sounded great on paper but flopped in practice.","pat":"Social mechanics that feel compelling in demos often have near-zero organic adoption when shipped.","url":"https://www.lennysnewsletter.com/p/failure","domain":"duolingo.com"},{"id":78,"stmt":"A product discovery community that had become the definitive launch platform for tech decided to replicate its model horizontally — spinning up separate communities for books, podcasts, games, and more, each with its own curated lists and daily rankings.","dec":"skip","co":"Product Hunt","yr":"2016","color":"#DA552F","expl":"Ryan Hoover later said plainly: 'We should not have tried to expand horizontally. We should have focused entirely vertically.' The expansions diluted the brand, spread a small team too thin, and were quietly wound down. The core product survived; the offshoots did not.","pat":"Category dominance is almost always worth more than category breadth. When you have something genuinely special in one niche, resist the urge to replicate it across others.","domain":"producthunt.com"},{"id":79,"stmt":"Duolingo launched in India using the phone's language setting to personalise onboarding — routing Hindi speakers away from the English course they actually wanted","dec":"skip","co":"Duolingo","yr":"2016","color":"#58CC02","expl":"Most Indian users wanted to learn English, but Duolingo detected the phone's language (Hindi) and surfaced a Hindi-language interface. The English course was invisible. Users churned at massive rates before the team identified the mismatch.","pat":"In multilingual markets, device settings and user intent frequently diverge — never assume they match.","url":"https://www.lennysnewsletter.com/p/failure","domain":"duolingo.com"},{"id":80,"stmt":"Duolingo held its achievement badge system for 6+ months trying to perfect it, then launched an MVP with just a single sign-up badge","dec":"skip","co":"Duolingo","yr":"2018","color":"#58CC02","expl":"Badges became a significant retention lever — but the delay cost Duolingo an estimated 8 months of growth. The team over-engineered before validating. The lesson: even a rough badge MVP would have revealed the signal far earlier.","pat":"Waiting for perfection on a high-potential mechanic costs more growth than a rough MVP ever would.","url":"https://www.lennysnewsletter.com/p/failure","domain":"duolingo.com"},{"id":81,"stmt":"Google built Google+ as a social network to directly compete with Facebook — driven by existential fear rather than identified user need","dec":"skip","co":"Google","yr":"2011","color":"#4285F4","expl":"Google+ was born from fear of Facebook, not user insight. Paul Adams, a researcher on the team, had data showing people wanted smaller contextual groups — not another open social graph. His findings were ignored. Google+ launched, peaked, and became a ghost town.","pat":"Products built from competitive panic rather than user insight almost never find product-market fit.","url":"https://www.lennysnewsletter.com/p/failure","domain":"google.com"},{"id":82,"stmt":"Pets.com ran a Super Bowl ad campaign, trying to out-spend rival pet e-commerce startups in a dotcom-era race for brand awareness","dec":"skip","co":"Pets.com","yr":"2000","color":"#F97316","expl":"Every competitor was burning VC money on the same TV advertising tactics. Nobody could win the arms race. Tom Conrad described how excess capital enabled irrational spending across the whole category. Pets.com burned through its cash and shut down just 268 days after its IPO.","pat":"When all well-funded rivals race to the same tactic, the only winners are the media companies selling the ads.","url":"https://www.lennysnewsletter.com/p/billion-dollar-failures-and-billion","domain":"pets.com"},{"id":83,"stmt":"Quibi launched with $1.75B raised, exclusively for mobile phones — and content couldn't be shared or screenshotted by users","dec":"skip","co":"Quibi","yr":"2020","color":"#EF4444","expl":"No sharing meant zero organic virality. Tom Conrad, who worked on the product, argued the bespoke content bet required $6–10B to work — not $1.75B. Mobile-only meant no TV, no casting, no social clips. After 6 months and $2B spent, Quibi shut down.","pat":"Premium content without virality is only viable with near-unlimited capital — and Quibi had neither.","url":"https://www.lennysnewsletter.com/p/billion-dollar-failures-and-billion","domain":"quibi.com"},{"id":84,"stmt":"Pandora doubled down on its radio-style algorithmic model while Spotify introduced full on-demand streaming to the same market","dec":"skip","co":"Pandora","yr":"2015","color":"#005483","expl":"Pandora's identity was built on curated radio — you couldn't pick songs. When Spotify launched on-demand streaming, Pandora stayed in its lane. Tom Conrad, Pandora's former CPO: 'We just got it wrong.' Pandora lost market leadership and was acquired by Sirius XM at a fraction of Spotify's valuation.","pat":"Core product constraints that feel like identity can quietly become fatal competitive blind spots.","url":"https://www.lennysnewsletter.com/p/billion-dollar-failures-and-billion","domain":"pandora.com"},{"id":85,"stmt":"Atlassian fully rewrote HipChat from scratch — branded 'HipChat Next Gen' — to compete with Slack after Slack's explosive launch","dec":"skip","co":"Atlassian","yr":"2017","color":"#0052CC","expl":"HipChat predated Slack in team messaging. When Slack took off, Atlassian flooded the team with developers — the platform buckled under the load, leading to a full rewrite. Tanguy Crusson, who led HipChat: 'Should you do a rewrite? Ask me now — never.' Atlassian sold HipChat to Slack in 2018.","pat":"Full rewrites under competitive pressure almost always take longer than expected and rarely recapture lost ground.","url":"https://www.lennysnewsletter.com/p/building-0-to-1-inside-atlassian-tanguy-crusson","domain":"atlassian.com"},{"id":86,"stmt":"A social media platform known for its public, permanent timeline launched disappearing posts — gone after 24 hours — to lower the stakes of sharing and encourage users who found the main feed too daunting to finally start posting.","dec":"skip","co":"Twitter","yr":"2020","color":"#1DA1F2","expl":"Twitter's Fleets launched in November 2020 and were shut down eight months later in August 2021. The format was designed to attract non-posters — but the people most inclined to use Stories already had Instagram and Snapchat. Fleets added clutter for power users without converting the lurkers it was built for.","pat":"Solving for users who don't engage often comes at the direct expense of users who do. Adding a new surface for a hypothetical audience rarely converts them — and always disrupts the existing one.","domain":"x.com"},{"id":87,"stmt":"An enterprise software company, after watching its messaging product lose ground to a fast-moving rival, rebuilt a new version from scratch with richer features — video, meetings, focus mode, and deep integrations — and launched it as a direct competitor.","dec":"skip","co":"Atlassian","yr":"2017","color":"#0052CC","expl":"Atlassian built Stride as an explicit Slack competitor after HipChat fell behind. Stride launched in 2017 with significant investment but never achieved meaningful adoption. In 2018, Atlassian sold both HipChat and Stride to Slack, officially conceding the market. The PM who led it later described it as a lesson in how hard it is to win a fight entirely on a competitor's terms.","pat":"Rewriting a product that already lost doesn't reset the competitive clock. If users have chosen an alternative, a more polished version of what they already rejected rarely changes the outcome.","domain":"atlassian.com"},{"id":88,"stmt":"A streaming service built a social layer on top of its core product — letting users see what friends were watching, share ratings, and get recommendations from their network — reasoning that social proof was the best possible discovery mechanism.","dec":"skip","co":"Netflix","yr":"2010","color":"#E50914","expl":"Netflix's social features were tested and eventually abandoned as a failed hypothesis. Users didn't want their viewing habits visible to friends. Watching is private, personal, and often revealing — and the social exposure risk outweighed any discovery benefit. The feature was quietly retired.","pat":"Not every successful social mechanic transfers to private consumption contexts. The intimacy of how someone uses a product shapes how willing they are to share it.","domain":"netflix.com"},{"id":89,"stmt":"A customer messaging platform rebuilt its entire pricing model from scratch — new tiers, bundled packages, and usage-based components — after deciding the old model was misaligned with how customers actually perceived value.","dec":"skip","co":"Intercom","yr":"2021","color":"#1F8EED","expl":"Intercom's pricing overhaul generated significant customer friction and accelerated churn. The head of product later described the period as one defined by compounded mistakes — pricing decisions made reactively to competitive pressure rather than grounded in genuine customer insight. The changes damaged relationships they'd spent years building.","pat":"Pricing changes made to win competitive comparisons rather than to reflect real value delivery break existing customer relationships without building new ones.","domain":"intercom.com"},{"id":90,"stmt":"A tech and e-commerce giant launched a flagship smartphone featuring exclusive hardware — 3D tilt effects, four front-facing cameras, a visual product search tool — priced to compete directly against Apple and Samsung at full retail price.","dec":"skip","co":"Amazon","yr":"2014","color":"#FF9900","expl":"The Amazon Fire Phone launched in June 2014 and was discontinued 13 months later. It moved fewer than 35,000 units in its first quarter, was discounted to 99 cents within months, and resulted in a $170M inventory write-off. Jeff Bezos later cited it as one of Amazon's most instructive public failures.","pat":"Distribution power does not confer hardware credibility. Consumers choose phones based on ecosystem and identity — neither of which can be bought by bundling features.","domain":"amazon.com"},{"id":91,"stmt":"A well-funded short-form video platform raised $1.75B, hired A-list Hollywood talent, and built an entire viewing experience designed exclusively for mobile portrait mode — with no TV or desktop support — then launched two weeks into the start of a global pandemic.","dec":"skip","co":"Quibi","yr":"2020","color":"#F5A623","expl":"Quibi launched in April 2020 — exactly when no one was commuting, travelling, or using their phone in short bursts outside the home. The mobile-only constraint eliminated any chance of casual at-home adoption. Quibi shut down in December 2020, six months after launch, returning nearly $1B to investors.","pat":"Platform constraints are invisible until they collide with reality. When the context a product is designed for suddenly disappears, no amount of content quality or funding can compensate.","domain":"quibi.com"},{"id":92,"stmt":"Dropbox killed Carousel (its photo app) and Mailbox (its email app) to go all-in on its core productivity product","dec":"ship","co":"Dropbox","yr":"2015","color":"#0061FF","expl":"Google Photos had just launched with free unlimited storage, nuking Dropbox's consumer value prop. Drew Houston cut both consumer apps and refocused entirely on productivity. Press turned brutal — 'Dropbox is dying.' But the focus worked: Dropbox went public in 2018 and today has 700M+ registered users.","pat":"The most painful cuts often create the most durable companies. Focus beats diversification when you're under existential threat.","url":"https://www.lennysnewsletter.com/p/behind-the-founder-drew-houston-dropbox","domain":"dropbox.com"},{"id":93,"stmt":"Netflix converted 7 movies to 3D and launched a 3D streaming experiment across partner smart TVs","dec":"skip","co":"Netflix","yr":"2012","color":"#E50914","expl":"Months of codec work, partner deals with Samsung and Sony, 7 titles converted to 3D. Aarthi Ramamurthy, who built the streaming SDK: 'Total disaster.' OEM partners pushed hard for 3D; Netflix followed. The 3D TV wave never arrived, and Netflix quietly pulled the plug.","pat":"Platform bets tied to consumer hardware fads (3D, VR, curved screens) fail at the same rate as the hardware itself.","url":"https://www.lennysnewsletter.com/p/hot-takes-and-optimism-from-techs","domain":"netflix.com"},{"id":94,"stmt":"Equals launched a freemium plan after users and investors demanded it — and signups quadrupled in the first few weeks","dec":"skip","co":"Equals","yr":"2022","color":"#6366F1","expl":"Bobby Pinero's Equals had friction-heavy onboarding (mandatory calls + upfront payment) that was working — revenue took off, they raised a $16M Series A. Then they launched freemium. Signups 4x'd immediately, but engagement, retention, and revenue all collapsed. Wrong users flooded in. Removing freemium fixed it.","pat":"Freemium that attracts users who never intended to pay isn't growth — it's noise that crowds out your real market.","url":"https://www.lennysnewsletter.com/p/lessons-from-going-freemium-a-decision","domain":"equals.com"}]
